/* global self */

// This file is imported by the Workbox service worker generated by next-pwa.
// It adds Web Push notification handlers.

self.addEventListener('push', (event) => {
  let data = {}
  try {
    data = event.data ? event.data.json() : {}
  } catch {
    data = { title: 'Vortexx', body: event.data ? String(event.data.text()) : '' }
  }

  const title = data.title || 'Vortexx'
  const body = data.body || ''
  const url = data.url || '/'

  const options = {
    body,
    icon: '/icon-192.png',
    badge: '/icon-192.png',
    data: { url },
  }

  event.waitUntil(self.registration.showNotification(title, options))
})

self.addEventListener('notificationclick', (event) => {
  event.notification.close()
  const url = (event.notification && event.notification.data && event.notification.data.url) || '/'

  event.waitUntil(
    self.clients
      .matchAll({ type: 'window', includeUncontrolled: true })
      .then((clientsArr) => {
        for (const client of clientsArr) {
          if (client.url && client.focus) return client.focus()
        }
        if (self.clients.openWindow) return self.clients.openWindow(url)
        return null
      })
  )
})
